import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}





// Helper function to map weather conditions to emoji icons
function getWeatherEmoji(condition: string): string {
  const normalized = (condition || '').toLowerCase().trim();
  const emojiMap: Record<string, string> = {
    sunny: '☀️',
    clear: '☀️',
    cloudy: '☁️',
    rainy: '🌧️',
    rain: '🌧️',
    snowy: '❄️',
    snow: '❄️',
    windy: '💨',
    foggy: '🌫️',
    fog: '🌫️',
    thunderstorm: '⛈️',
  };
  return emojiMap[normalized] || '☁️';
}

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract


  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Current Weather Section */}
        <Card shadow="md" padding="var(--ggui-spacing-6)">
          <Stack gap="var(--ggui-spacing-4)" align="center">
            <Heading level={2}>{props.city}</Heading>
            <Text size="4xl" weight="bold" color="var(--ggui-color-primary-600)">{props.temperature}°{props.unit}</Text>
            <Row gap="var(--ggui-spacing-3)" align="center" justify="center">
               <Icon name={getWeatherEmoji(props.condition)} size={48} color="var(--ggui-color-primary-600)" />
              <Text size="lg" variant="body">{props.condition}</Text>
            </Row>
            <Divider margin="var(--ggui-spacing-4)" />
            <Row gap="var(--ggui-spacing-8)" justify="center">
              <Stack gap="var(--ggui-spacing-1)" align="center">
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">Humidity</Text>
                <Text size="lg" weight="semibold">{props.humidity}%</Text>
              </Stack>
              <Stack gap="var(--ggui-spacing-1)" align="center">
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">Wind Speed</Text>
                <Text size="lg" weight="semibold">{props.windSpeed} m/s</Text>
              </Stack>
            </Row>
          </Stack>
        </Card>

        {/* 5-Day Forecast */}
        <Card shadow="md" padding="var(--ggui-spacing-6)">
          <Stack gap="var(--ggui-spacing-3)">
            <Heading level={3}>5-Day Forecast</Heading>
            <Row gap="var(--ggui-spacing-3)" wrap>
              {props.forecast && props.forecast.length > 0 ? (
                props.forecast.map((day, index) => (
                  <Button key={index} variant="ghost" as={Clickable} onClick={() => {}} aria-label={`${day.day || `Day ${index + 1}`}: ${day.high}° high, ${day.low}° low`}>
                    <Card padding="var(--ggui-spacing-4)" shadow="sm" border>
                      <Stack gap="var(--ggui-spacing-2)" align="center">
                        <Text variant="label" weight="semibold">{day.day || `Day ${index + 1}`}</Text>
                        <Icon name={day.icon || '☁️'} size={32} color="var(--ggui-color-primary-600)" />
                        <Text variant="bodySmall">{day.high}° / {day.low}°</Text>
                      </Stack>
                    </Card>
                  </Button>
                ))
              ) : (
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">No forecast data available</Text>
              )}
            </Row>
          </Stack>
        </Card>
      </Stack>
    </Container>

  );
}

// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





// Place helper components here if needed

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  // Actions — fire-and-forget to agent
  const submit = useAction<ActionSubmitPayload>('submit'); // Called with all collected answers as a structured object

  // State for multi-step survey
  const [currentStep, setCurrentStep] = useState(1);
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    satisfaction: 0,
    features: [] as string[],
    comments: '',
  });
  const [errors, setErrors] = useState({
    name: '',
    email: '',
  });

  // Validation helpers
  const isValidEmail = (email: string): boolean => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return emailRegex.test(email);
  };
  const isStep1Valid = (): boolean => {
    const newErrors = { name: '', email: '' };
    let isValid = true;
    if (!formData.name.trim()) {
      newErrors.name = 'Name is required';
      isValid = false;
    }
    if (!formData.email.trim()) {
      newErrors.email = 'Email is required';
      isValid = false;
    } else if (!isValidEmail(formData.email)) {
      newErrors.email = 'Please enter a valid email';
      isValid = false;
    }
    setErrors(newErrors);
    return isValid;
  };
  const isStep2Valid = (): boolean => {
    return formData.satisfaction > 0;
  };
  const isStep3Valid = (): boolean => {
    return formData.features.length > 0;
  };
  // Navigation handlers
  const handleNext = useCallback(() => {
    if (currentStep === 1) {
      if (isStep1Valid()) {
        setCurrentStep(2);
      }
    } else if (currentStep === 2) {
      if (isStep2Valid()) {
        setCurrentStep(3);
      }
    } else if (currentStep === 3) {
      if (isStep3Valid()) {
        setCurrentStep(4);
      }
    }
  }, [currentStep, formData]);
  const handleBack = useCallback(() => {
    if (currentStep > 1) {
      setCurrentStep(currentStep - 1);
    }
  }, [currentStep]);
  const handleSubmit = useCallback(() => {
    submit({
      name: formData.name,
      email: formData.email,
      satisfaction: formData.satisfaction,
      features: formData.features,
      comments: formData.comments,
    });
  }, [formData, submit]);
  // Determine if Next button should be enabled
  const isNextDisabled = useMemo(() => {
    if (currentStep === 1) return !formData.name.trim() || !formData.email.trim() || !isValidEmail(formData.email);
    if (currentStep === 2) return formData.satisfaction === 0;
    if (currentStep === 3) return formData.features.length === 0;
    return false;
  }, [currentStep, formData]);
  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Progress indicator */}
        <Box>
          <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
            Step {currentStep} of 4
          </Text>
          <Spacer size={8} />
          <Progress
            value={currentStep}
            max={4}
            variant="default"
            size="md"
          />
        </Box>
        {/* Step 1: Name and Email */}
        {currentStep === 1 && (
          <Card shadow="md" padding="var(--ggui-spacing-6)">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>Your Information</Heading>
              <Input
                label="Name"
                placeholder="John Doe"
                value={formData.name}
                onChange={(value) =>
                  setFormData({ ...formData, name: value })
                }
                error={errors.name}
                required
              />
              <Input
                label="Email"
                type="email"
                placeholder="john@example.com"
                value={formData.email}
                onChange={(value) =>
                  setFormData({ ...formData, email: value })
                }
                error={errors.email}
                required
              />
            </Stack>
          </Card>
        )}
        {/* Step 2: Satisfaction Rating */}
        {currentStep === 2 && (
          <Card shadow="md" padding="var(--ggui-spacing-6)">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>How Satisfied Are You?</Heading>
              <RadioGroup
                label="Satisfaction Rating"
                value={String(formData.satisfaction)}
                onChange={(value) =>
                  setFormData({ ...formData, satisfaction: parseInt(value, 10) })
                }
                options={props.satisfactionLabels.map((label, idx) => ({
                  value: String(idx + 1),
                  label,
                }))}
                direction="vertical"
              />
            </Stack>
          </Card>
        )}
        {/* Step 3: Feature Interests */}
        {currentStep === 3 && (
          <Card shadow="md" padding="var(--ggui-spacing-6)">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>What Features Interest You?</Heading>
              <Stack gap="var(--ggui-spacing-2)">
                {props.featureOptions.map((feature) => (
                  <Checkbox
                    key={feature}
                    label={feature}
                    checked={formData.features.includes(feature)}
                    onChange={(checked) => {
                      if (checked) {
                        setFormData({
                          ...formData,
                          features: [...formData.features, feature],
                        });
                      } else {
                        setFormData({
                          ...formData,
                          features: formData.features.filter(
                            (f) => f !== feature
                          ),
                        });
                      }
                    }}
                  />
                ))}
              </Stack>
            </Stack>
          </Card>
        )}
        {/* Step 4: Comments & Review */}
        {currentStep === 4 && (
          <Card shadow="md" padding="var(--ggui-spacing-6)">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>Comments & Review</Heading>
              {/* Comments input */}
              <TextArea
                label="Additional Comments"
                placeholder="Tell us what you think..."
                value={formData.comments}
                onChange={(value) =>
                  setFormData({ ...formData, comments: value })
                }
                maxLength={500}
                showCount
                rows={5}
              />
              {/* Review summary */}
              <Box padding="var(--ggui-spacing-4)" background="var(--ggui-color-primary-50)" borderRadius="var(--ggui-shape-radius-md)">
                <Stack gap="var(--ggui-spacing-3)">
                  <Heading level={4} color="var(--ggui-color-primary-900)">
                    Review Your Answers
                  </Heading>
                  <Stack gap="var(--ggui-spacing-2)">
                    <Row gap="var(--ggui-spacing-2)" align="start">
                      <Text variant="label" weight="semibold">
                        Name:
                      </Text>
                      <Text>{formData.name}</Text>
                    </Row>
                    <Row gap="var(--ggui-spacing-2)" align="start">
                      <Text variant="label" weight="semibold">
                        Email:
                      </Text>
                      <Text>{formData.email}</Text>
                    </Row>
                    <Row gap="var(--ggui-spacing-2)" align="start">
                      <Text variant="label" weight="semibold">
                        Satisfaction:
                      </Text>
                      <Text>
                        {formData.satisfaction > 0
                          ? props.satisfactionLabels[formData.satisfaction - 1]
                          : 'Not selected'}
                      </Text>
                    </Row>
                    <Row gap="var(--ggui-spacing-2)" align="start">
                      <Text variant="label" weight="semibold">
                        Features:
                      </Text>
                      <Stack gap="var(--ggui-spacing-1)">
                        {formData.features.length > 0 ? (
                          formData.features.map((feature) => (
                            <Badge
                              key={feature}
                              variant="primary"
                              size="sm"
                            >
                              {feature}
                            </Badge>
                          ))
                        ) : (
                          <Text color="var(--ggui-color-onSurfaceVariant)">
                            None selected
                          </Text>
                        )}
                      </Stack>
                    </Row>
                    {formData.comments && (
                      <Row gap="var(--ggui-spacing-2)" align="start">
                        <Text variant="label" weight="semibold">
                          Comments:
                        </Text>
                        <Text>{formData.comments}</Text>
                      </Row>
                    )}
                  </Stack>
                </Stack>
              </Box>
            </Stack>
          </Card>
        )}
        {/* Navigation buttons */}
        <Row gap="var(--ggui-spacing-3)" justify="between">
          <Button
            variant="outline"
            onClick={handleBack}
            disabled={currentStep === 1}
          >
            Back
          </Button>
          {currentStep === 4 ? (
            <Button
              variant="primary"
              onClick={handleSubmit}
            >
              Submit
            </Button>
          ) : (
            <Button
              variant="primary"
              onClick={handleNext}
              disabled={isNextDisabled}
            >
              Next
            </Button>
          )}
        </Row>
      </Stack>
    </Container>
  );
}

// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column?: string; title?: string; priority?: 'low' | 'medium' | 'high' } };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };




// Task Card Component
interface TaskCardProps {
  task: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string };
  columns: Array<{ id?: string; name?: string }>;
  onEdit: (id: string, title: string) => void;
  onMove: (id: string, newColumn: string) => void;
}

function TaskCard({ task, columns, onEdit, onMove }: TaskCardProps) {
  const [isEditing, setIsEditing] = useState(false);
  const [editTitle, setEditTitle] = useState(task.title || '');
  const [showMoveMenu, setShowMoveMenu] = useState(false);

  const getPriorityColor = (priority?: string) => {
    switch (priority) {
      case 'high':
        return 'var(--ggui-color-error-500)';
      case 'medium':
        return 'var(--ggui-color-warning-500)';
      case 'low':
      default:
        return 'var(--ggui-color-success-500)';
    }
  };

  const handleSaveEdit = () => {
    if (editTitle.trim()) {
      onEdit(task.id || '', editTitle);
      setIsEditing(false);
    }
  };

  const handleDoubleClick = () => {
    setIsEditing(true);
    setEditTitle(task.title || '');
  };

  const getPriorityLabel = (priority?: string) => {
    switch (priority) {
      case 'high':
        return 'High';
      case 'medium':
        return 'Medium';
      case 'low':
        return 'Low';
      default:
        return 'Low';
    }
  };

  return (
    <Card
      padding="var(--ggui-spacing-3)"
      shadow="sm"
      border
      tabIndex={0}
      aria-label={`Task: ${task.title || 'Untitled'}. Double-click or press Enter to edit.`}
      onKeyDown={(e) => {
        if (e.key === 'Enter' && !isEditing) {
          handleDoubleClick();
        }
      }}
      onDoubleClick={handleDoubleClick}
      style={{ cursor: 'pointer' }}
    >
      <Stack gap="var(--ggui-spacing-2)">
        {isEditing ? (
          <Stack gap="var(--ggui-spacing-2)" direction="horizontal">
            <Input
              label="Edit task"
              value={editTitle}
              onChange={setEditTitle}
              placeholder="Task title"
            />
            <Button variant="primary" size="sm" onClick={handleSaveEdit}>
              Save
            </Button>
            <Button variant="ghost" size="sm" onClick={() => setIsEditing(false)}>
              Cancel
            </Button>
          </Stack>
        ) : (
          <>
            <Text variant="label">{task.title || 'Untitled'}</Text>
            <Row gap="var(--ggui-spacing-2)" align="center">
              <Badge
                variant="default"
                size="sm"
                style={{ background: getPriorityColor(task.priority) }}
              >
                {getPriorityLabel(task.priority)}
              </Badge>
              {task.assignee && (
                <Avatar name={task.assignee} size="xs" />
              )}
            </Row>
            {task.dueDate && (
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                Due: {task.dueDate}
              </Text>
            )}
            <Row gap="var(--ggui-spacing-2)" justify="between" align="center">
              <Button variant="ghost" size="sm" onClick={() => setIsEditing(true)}>
                ✎ Edit
              </Button>
              <Dropdown
                trigger={<Button variant="ghost" size="sm">Move</Button>}
                options={columns
                  .filter(col => col.id !== task.column)
                  .map(col => ({ value: col.id || '', label: col.name || col.id || '' }))
                }
                value={task.column || ''}
                onChange={(colId) => onMove(task.id || '', colId)}
              />
            </Row>
          </>
        )}
      </Stack>
    </Card>
  );
}


export default function Component(props: Props) {
  // Actions — fire-and-forget to agent
  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate');

  // Streams — real-time from agent (.latest, .all)
  const taskChanged = useStream<StreamTaskChanged>('taskChanged');

  // Local state for tasks and UI
  const [tasks, setTasks] = useState(props.tasks || []);
  const [addingTaskInColumn, setAddingTaskInColumn] = useState<string | null>(null);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');

  // Merge incoming stream updates into local tasks
  useEffect(() => {
    if (taskChanged.latest?.task) {
      const updatedTask = taskChanged.latest.task;
      setTasks(prevTasks => {
        const existing = prevTasks.find(t => t.id === updatedTask.id);
        if (taskChanged.latest?.action === 'delete' || taskChanged.latest?.action === undefined) {
          // For unknown actions, assume update
          if (existing) {
            return prevTasks.map(t => t.id === updatedTask.id ? { ...t, ...updatedTask } : t);
          } else {
            return [...prevTasks, updatedTask];
          }
        } else if (taskChanged.latest?.action === 'delete') {
          return prevTasks.filter(t => t.id !== updatedTask.id);
        }
        if (existing) {
          return prevTasks.map(t => t.id === updatedTask.id ? { ...t, ...updatedTask } : t);
        }
        return [...prevTasks, updatedTask];
      });
    }
  }, [taskChanged.latest]);

  // Handlers
  const handleEditTask = useCallback((taskId: string, newTitle: string) => {
    const task = tasks.find(t => t.id === taskId);
    setTasks(prevTasks =>
      prevTasks.map(t => t.id === taskId ? { ...t, title: newTitle } : t)
    );
    taskUpdate({ action: 'edit', taskId, data: { title: newTitle, column: task?.column || 'todo', priority: task?.priority || 'medium' } });
  }, [tasks, taskUpdate]);

  const handleMoveTask = useCallback((taskId: string, newColumn: string) => {
    setTasks(prevTasks =>
      prevTasks.map(t => t.id === taskId ? { ...t, column: newColumn } : t)
    );
    taskUpdate({ action: 'move', taskId, data: { column: newColumn } });
  }, [taskUpdate]);

  const handleAddTask = useCallback((columnId: string) => {
    if (newTaskTitle.trim()) {
      const newTaskId = `task-${Date.now()}`;
      const newTask = {
        id: newTaskId,
        title: newTaskTitle,
        priority: newTaskPriority,
        column: columnId,
      };
      setTasks(prevTasks => [...prevTasks, newTask]);
