                    </Stack>

                    {/* Add Task Form */}
                    {isAddingInThisColumn ? (
                      <Stack gap="var(--ggui-spacing-2)">
                        <Input
                          label="Task title"
                          value={newTaskTitle}
                          onChange={setNewTaskTitle}
