                        />
                        <Select
                          label="Priority"
                          value={newTaskPriority}
                          onChange={(val) => setNewTaskPriority(val as 'low' | 'medium' | 'high')}
                          options={[
                            { value: 'low', label: 'Low' },
                            { value: 'medium', label: 'Medium' },
                            { value: 'high', label: 'High' },
                          ]}
                        />
                        <Row gap="var(--ggui-spacing-2)" justify="end">
                          <Button
                            variant="ghost"
                            size="sm"
                            onClick={() => {
                              setAddingTaskInColumn(null);
                              setNewTaskTitle('');
                            }}
                          >
                            Cancel
                          </Button>
                          <Button
                            variant="primary"
                            size="sm"
                            onClick={() => handleAddTask(column.id || '')}
                          >
                            Add Task
                          </Button>
                        </Row>
                      </Stack>
                    ) : (
                      <Button
                        variant="outline"
                        fullWidth
                        onClick={() => setAddingTaskInColumn(column.id || '')}
                      >
                        + Add Task
                      </Button>
                    )}
                  </Stack>
                </Card>
              </Box>
            );
          })}
        </Row>
      </Stack>
    </Container>
  );
}

