            </Stack>

            {/* Add to Cart Button */}
            <Button
              variant="primary"
              size="lg"
              fullWidth
              onClick={handleAddToCart}
              disabled={isOutOfStock}
            >
              {isOutOfStock ? 'Out of Stock' : 'Add to Cart'}
            </Button>
          </Stack>
        </Card>
      </Stack>
    </Container>
  );
