      handleSendMessage();
    }
  }, [handleSendMessage]);

  // Get active typing sender
  const typingSender = typing.latest?.active ? typing.latest.sender : null;

  // Format timestamp
  const formatTime = (timestamp?: string) => {
    if (!timestamp) return '';
    const date = new Date(timestamp);
    return date.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit' });
  };

  // Group consecutive messages by sender
  const groupedMessages = useMemo(() => {
    const groups: Array<{
      sender?: string;
      messages: Array<{ text?: string; timestamp?: string }>;
    }> = [];

    messages.forEach((msg) => {
      const lastGroup = groups[groups.length - 1];
      if (lastGroup && lastGroup.sender === msg.sender) {
        lastGroup.messages.push({ text: msg.text, timestamp: msg.timestamp });
      } else {
        groups.push({
          sender: msg.sender,
          messages: [{ text: msg.text, timestamp: msg.timestamp }],
        });
      }
    });

    return groups;
  }, [messages]);

  return (
    <Container maxWidth='xl' padding='var(--ggui-spacing-6)'>
      <Card shadow='md' radius='lg' border={true} padding='var(--ggui-spacing-0)'>
        <Stack direction='vertical' gap='0' align='stretch'>
          {/* Header */}
          <Box padding='var(--ggui-spacing-4)' background='var(--ggui-color-primary-50)' borderRadius='var(--ggui-shape-radius-lg)'>
            <Row align='center' justify='between' gap='var(--ggui-spacing-3)'>
              <Stack direction='vertical' gap='var(--ggui-spacing-1)' align='start'>
                <Heading level={3} color='var(--ggui-color-primary-900)'>
                  {props.title}
                </Heading>
              </Stack>
              <Badge variant='primary' size='md'>
                {props.participantCount} participant{props.participantCount !== 1 ? 's' : ''}
              </Badge>
            </Row>
          </Box>

          <Divider orientation='horizontal' margin='0' color='var(--ggui-color-outline)' />

          {/* Messages area */}
          <Box
            padding='var(--ggui-spacing-4)'
            background='var(--ggui-color-surface)'
            borderRadius='0'
            style={{
              overflowY: 'auto',
              height: '400px',
              display: 'flex',
              flexDirection: 'column',
              gap: 'var(--ggui-spacing-3)',
            }}
          >
            {groupedMessages.length === 0 ? (
              <Box
                padding='var(--ggui-spacing-8)'
                background='var(--ggui-color-surfaceVariant)'
                borderRadius='var(--ggui-shape-radius-md)'
                style={{ textAlign: 'center' }}
              >
                <Text variant='bodySmall' color='var(--ggui-color-onSurfaceVariant)'>
                  No messages yet. Start the conversation!
                </Text>
              </Box>
            ) : (
              groupedMessages.map((group, groupIdx) => {
                const isCurrentUser = group.sender === props.currentUser;
                return (
                  <Stack
                    key={groupIdx}
                    direction='vertical'
                    gap='var(--ggui-spacing-1)'
                    align={isCurrentUser ? 'end' : 'start'}
                  >
                    {group.messages.map((msg, msgIdx) => (
                      <Card
                        key={msgIdx}
                        padding='var(--ggui-spacing-3)'
                        shadow='sm'
                        radius='md'
                        border={false}
                        background={
                          isCurrentUser
                            ? 'var(--ggui-color-primary-600)'
                            : 'var(--ggui-color-surfaceVariant)'
                        }
                        style={{ maxWidth: '60%' }}
                      >
                        <Stack direction='vertical' gap='var(--ggui-spacing-1)' align='stretch'>
                          <Text
                            variant='caption'
                            color={
                              isCurrentUser
                                ? 'var(--ggui-color-primary-50)'
                                : 'var(--ggui-color-onSurfaceVariant)'
                            }
                            weight='medium'
                          >
                            {group.sender}
                          </Text>
                          <Text
                            variant='body'
                            color={
                              isCurrentUser
                                ? 'var(--ggui-color-primary-50)'
                                : 'var(--ggui-color-onSurface)'
                            }
                          >
                            {msg.text}
                          </Text>
                          <Text
                            variant='caption'
                            color={
                              isCurrentUser
                                ? 'var(--ggui-color-primary-50)'
                                : 'var(--ggui-color-onSurfaceVariant)'
                            }
                          >
                            {formatTime(msg.timestamp)}
                          </Text>
                        </Stack>
                      </Card>
                    ))}
                    {/* Typing indicator */}
                    {typingSender && (
                      <Box
                        padding='var(--ggui-spacing-2)'
                        style={{
                          display: 'flex',
                          flexDirection: 'column',
                          gap: 'var(--ggui-spacing-1)',
                          alignItems: 'flex-start',
                        }}
                        role='status'
                      >
                        <Text variant='caption' color='var(--ggui-color-onSurfaceVariant)'>
                          {typingSender} is typing
                          <span
                            style={{
                              display: 'inline-block',
                              animation: 'ggui-pulse 1.5s ease-in-out infinite',
                            }}
                            aria-hidden='true'
                          >
                            ....
                          </span>
                        </Text>
                      </Box>
                    )}
                  </Stack>
                );
              })}
            {/* Auto-scroll anchor */}
            <Box ref={messagesEndRef} style={{ display: 'none' }} />
          </Box>

          {/* Input area */}
          <Box padding='var(--ggui-spacing-4)' background='var(--ggui-color-surface)' borderRadius='0'>
            <Stack direction='horizontal' gap='var(--ggui-spacing-2)' align='end'>
              <TextArea
                label='Message'
                value={inputValue}
                onChange={setInputValue}
                placeholder='Type your message...'
                rows={2}
                onKeyDown={handleKeyDown}
                style={{ flexGrow: 1 }}
              />
              <Button
                variant='primary'
                size='md'
                onClick={handleSendMessage}
                disabled={!inputValue.trim()}
              >
                Send
              </Button>
            </Stack>
          </Box>
        </Stack>
      </Card>
    </Container>
  );
}

