// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion, MotionKeyframes } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useStream } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>; // Array of stocks with symbol, name, price, change, changePercent
}


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: Updated price data for one or more stocks */
type StreamPriceUpdate = { symbol?: string; price?: number; change?: number; changePercent?: number };

/** Stream event: Market open/closed status update */
type StreamMarketStatus = { status?: 'open' | 'closed' | 'pre-market' | 'after-hours'; timestamp?: string };




// Stock card component for individual stock display
// Stock card component for individual stock display
function StockCard({ stock, isUpdating }: { stock: { symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }; isUpdating: boolean }) {
  const isPositive = (stock.change ?? 0) >= 0;
  const changeColor = isPositive ? 'var(--ggui-color-success-500)' : 'var(--ggui-color-error-500)';
  const borderColor = isPositive ? 'var(--ggui-color-success-200)' : 'var(--ggui-color-error-200)';
  const backgroundColor = isPositive ? 'var(--ggui-color-success-50)' : 'var(--ggui-color-error-50)';
  const arrow = isPositive ? '▲' : '▼';

  return (
    <Card
      as={Hoverable}
      padding="var(--ggui-spacing-4)"
      shadow="md"
      radius="lg"
      border={true}
      hoverStyle={{ shadow: 'lg' }}
      style={{
        borderColor: borderColor,
        animation: isUpdating ? 'ggui-flash 600ms ease-out' : 'none',
        '--ggui-flash-color': backgroundColor,
      } as React.CSSProperties}
    >
      <Stack gap="var(--ggui-spacing-3)" align="start">
        <Text variant="overline" size="2xl" weight="bold" color="var(--ggui-color-onSurface)">
          {stock.symbol || 'N/A'}
        </Text>
        <Text variant="body" size="sm" color="var(--ggui-color-onSurfaceVariant)">
          {stock.name || 'Unknown'}
        </Text>
        <Text variant="bodyLarge" size="2xl" weight="bold" color="var(--ggui-color-onSurface)">
          ${(stock.price ?? 0).toFixed(2)}
        </Text>
        <Row gap="var(--ggui-spacing-2)" align="center">
          <Text variant="body" size="base" weight="semibold" color={changeColor}>
            {arrow} {stock.change?.toFixed(2) || '0.00'} ({(stock.changePercent ?? 0).toFixed(2)}%)
          </Text>
        </Row>
      </Stack>
    </Card>
  );
}

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract

  // Streams — real-time from agent (.latest, .all)
  const priceUpdate = useStream<StreamPriceUpdate>('priceUpdate'); // Updated price data for one or more stocks
  const marketStatus = useStream<StreamMarketStatus>('marketStatus'); // Market open/closed status update

  // State management
  const [stocks, setStocks] = useState(props.stocks || []);
  const [lastUpdated, setLastUpdated] = useState<Date>(new Date());
  const [updatingSymbols, setUpdatingSymbols] = useState<Set<string>>(new Set());
  const updateTimeoutRef = useRef<NodeJS.Timeout | null>(null);

  // Merge incoming price updates into stock data
  useEffect(() => {
    if (priceUpdate.latest) {
      const update = priceUpdate.latest;
      if (update.symbol) {
        setStocks((prevStocks) =>
          prevStocks.map((stock) =>
            stock.symbol === update.symbol
              ? {
                  ...stock,
                  price: update.price ?? stock.price,
                  change: update.change ?? stock.change,
                  changePercent: update.changePercent ?? stock.changePercent,
                }
              : stock
          )
        );

        // Mark this symbol as updating to trigger flash animation
        setUpdatingSymbols((prev) => new Set(prev).add(update.symbol!));
        setLastUpdated(new Date());

        // Clear the updating flag after animation completes
        if (updateTimeoutRef.current) {
          clearTimeout(updateTimeoutRef.current);
        }
        updateTimeoutRef.current = setTimeout(() => {
          setUpdatingSymbols((prev) => {
            const newSet = new Set(prev);
            newSet.delete(update.symbol!);
            return newSet;
          });
        }, 600);
      }
    }
  }, [priceUpdate.latest]);

  // Update stocks from props if they change
  useEffect(() => {
    setStocks(props.stocks || []);
  }, [props.stocks]);

  // Cleanup timeout on unmount
  useEffect(() => {
    return () => {
      if (updateTimeoutRef.current) {
        clearTimeout(updateTimeoutRef.current);
      }
    };
  }, []);

  const marketStatusText = useMemo(() => {
    const status = marketStatus.latest?.status || 'closed';
    switch (status) {
      case 'open':
        return { text: 'Market Open', color: 'var(--ggui-color-success-600)' };
      case 'closed':
        return { text: 'Market Closed', color: 'var(--ggui-color-error-600)' };
      case 'pre-market':
        return { text: 'Pre-Market', color: 'var(--ggui-color-warning-600)' };
      case 'after-hours':
        return { text: 'After Hours', color: 'var(--ggui-color-warning-600)' };
      default:
        return { text: 'Unknown', color: 'var(--ggui-color-onSurfaceVariant)' };
    }
  }, [marketStatus.latest?.status]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <MotionKeyframes />
      <Stack gap="var(--ggui-spacing-6)" align="stretch">
        {/* Header Section */}
        <Row gap="var(--ggui-spacing-4)" justify="between" align="center">
          <Heading level={1} color="var(--ggui-color-onSurface)">
            Market Watch
          </Heading>
          <Stack direction="horizontal" gap="var(--ggui-spacing-3)" align="center">
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
              Last Updated: {lastUpdated.toLocaleTimeString()}
            </Text>
            <Badge variant={marketStatus.latest?.status === 'open' ? 'success' : 'default'}>{marketStatusText.text}</Badge>
          </Stack>
        </Row>

        {/* Stock Cards Grid */}
        <div
          style={{
            display: 'grid',
            gridTemplateColumns: '1fr',
            gap: 'var(--ggui-spacing-4)',
          }}
          className="stock-grid"
        >
          <style>{`
            @media (min-width: 768px) {
              .stock-grid {
                grid-template-columns: repeat(3, 1fr);
              }
            }
            @media (max-width: 640px) {
              .stock-grid {
                grid-template-columns: 1fr;
              }
            }
          `}</style>
          {stocks && stocks.length > 0 ? (
            stocks.map((stock) => (
              <StockCard
                key={stock.symbol}
                stock={stock}
                isUpdating={updatingSymbols.has(stock.symbol || '')}
              />
            ))
          ) : (
            <Box padding="var(--ggui-spacing-6)" textAlign="center">
              <Text color="var(--ggui-color-onSurfaceVariant)">No stocks to display</Text>
            </Box>
          )}
        </div>
      </Stack>
    </Container>
  );
}

// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  initialProfile: { name?: string; email?: string; avatar?: string; role?: string; emailNotifications?: boolean; theme?: string }; // Pre-filled profile data for editing (all fields optional)
  avatarOptions: string[]; // Available avatar emojis to choose from
  roleOptions: string[]; // Available role options for the dropdown
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all profile data when user completes onboarding */
type ActionCompletePayload = { name: string; email: string; avatar: string; role: string; emailNotifications: boolean; theme: string };


// Step indicator component
function StepIndicator({ currentStep, totalSteps }: { currentStep: number; totalSteps: number }) {
  return (
    <Stack gap="var(--ggui-spacing-4)" align="center">
      <Text variant="label">Step {currentStep} of {totalSteps}</Text>
      <Progress value={(currentStep / totalSteps) * 100} variant="default" size="md" />
    </Stack>
  );
}

// Avatar selector component
function AvatarSelector({ selected, options, onSelect }: { selected: string; options: string[]; onSelect: (avatar: string) => void }) {
  return (
    <Row gap="var(--ggui-spacing-4)" align="center" wrap>
      {options.map((avatar) => (
        <Box
          key={avatar}
          as={Clickable}
          onClick={() => onSelect(avatar)}
          padding="var(--ggui-spacing-2)"
          borderRadius="var(--ggui-shape-radius-md)"
          background={selected === avatar ? 'var(--ggui-color-primary-100)' : 'var(--ggui-color-surfaceVariant)'}
          style={{ cursor: 'pointer', transition: 'background-color 200ms ease-in-out' }}
        >
          <Text size="3xl">{avatar}</Text>
        </Box>
      ))}
    </Row>
  );
}

// Validation helpers
function isValidEmail(email: string): boolean {
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
}

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const complete = useAction<ActionCompletePayload>('complete'); // Called with all profile data when user completes onboarding

  // State management
  const [currentStep, setCurrentStep] = useState(1);
  const [formData, setFormData] = useState({
    name: props.initialProfile.name || '',
    email: props.initialProfile.email || '',
    avatar: props.initialProfile.avatar || props.avatarOptions[0] || '',
    role: props.initialProfile.role || '',
    emailNotifications: props.initialProfile.emailNotifications ?? true,
    theme: props.initialProfile.theme || 'light',
  });

  // Validation state
  const [errors, setErrors] = useState<Record<string, string>>({});

  // Validation logic
  const validateStep = (step: number): boolean => {
    const newErrors: Record<string, string> = {};
    if (step === 1) {
      if (!formData.name.trim()) newErrors.name = 'Name is required';
      if (!formData.email.trim()) newErrors.email = 'Email is required';
      else if (!isValidEmail(formData.email)) newErrors.email = 'Invalid email format';
    }
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  // Navigation handlers
  const handleNext = () => {
    if (validateStep(currentStep)) {
      setCurrentStep(currentStep + 1);
    }
  };

  const handleBack = () => {
    if (currentStep > 1) {
      setCurrentStep(currentStep - 1);
    }
  };

  const handleComplete = () => {
    complete({
      name: formData.name,
      email: formData.email,
      avatar: formData.avatar,
      role: formData.role,
      emailNotifications: formData.emailNotifications,
      theme: formData.theme,
    });
  };

  // Render step content
  const renderStepContent = () => {
    switch (currentStep) {
      case 1:
        return (
          <Stack gap="var(--ggui-spacing-6)">
            <Heading level={2}>Profile Setup</Heading>
            <Input
              label="Name"
              required
              value={formData.name}
              onChange={(value) => setFormData({ ...formData, name: value })}
              error={errors.name}
              placeholder="Your full name"
            />
            <Input
              label="Email"
              required
              type="email"
              value={formData.email}
              onChange={(value) => setFormData({ ...formData, email: value })}
              error={errors.email}
              placeholder="you@example.com"
            />
            <Stack gap="var(--ggui-spacing-2)">
              <Text variant="label">Avatar</Text>
              <AvatarSelector
                selected={formData.avatar}
                options={props.avatarOptions}
                onSelect={(avatar) => setFormData({ ...formData, avatar })}
              />
            </Stack>
          </Stack>
        );
      case 2:
        return (
          <Stack gap="var(--ggui-spacing-6)">
            <Heading level={2}>Preferences</Heading>
            <Select
              label="Role"
              value={formData.role}
              onChange={(value) => setFormData({ ...formData, role: value })}
              options={props.roleOptions.map((role) => ({ value: role, label: role }))}
              placeholder="Select a role"
            />
            <Toggle
              label="Email Notifications"
              checked={formData.emailNotifications}
              onChange={(checked) => setFormData({ ...formData, emailNotifications: checked })}
            />
            <Toggle
              label="Dark Theme"
              checked={formData.theme === 'dark'}
              onChange={(checked) => setFormData({ ...formData, theme: checked ? 'dark' : 'light' })}
            />
          </Stack>
        );
      case 3:
        return (
          <Stack gap="var(--ggui-spacing-6)">
            <Heading level={2}>Review & Confirm</Heading>
            <Card padding="var(--ggui-spacing-4)" shadow="md">
              <Stack gap="var(--ggui-spacing-4)">
                <Box>
                  <Text variant="label">Name</Text>
                  <Text>{formData.name}</Text>
                </Box>
                <Box>
                  <Text variant="label">Email</Text>
                  <Text>{formData.email}</Text>
                </Box>
                <Box>
                  <Text variant="label">Avatar</Text>
                  <Text size="2xl">{formData.avatar}</Text>
                </Box>
                <Box>
                  <Text variant="label">Role</Text>
                  <Text>{formData.role}</Text>
                </Box>
                <Box>
                  <Text variant="label">Email Notifications</Text>
                  <Text>{formData.emailNotifications ? 'Enabled' : 'Disabled'}</Text>
                </Box>
                <Box>
                  <Text variant="label">Theme</Text>
                  <Text>{formData.theme === 'dark' ? 'Dark' : 'Light'}</Text>
                </Box>
              </Stack>
            </Card>
          </Stack>
        );
      default:
        return null;
    }
  };

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-8)" align="center">
        <StepIndicator currentStep={currentStep} totalSteps={3} />
        <Card padding="var(--ggui-spacing-6)" shadow="md" style={{ width: '100%', maxWidth: '600px' }}>
          {renderStepContent()}
          <Divider margin="var(--ggui-spacing-6)" />
          <Row gap="var(--ggui-spacing-4)" justify="between">
            <Button
              variant="ghost"
              onClick={handleBack}
              disabled={currentStep === 1}
            >
              Back
            </Button>
            {currentStep < 3 ? (
              <Button
                variant="primary"
                onClick={handleNext}
                disabled={currentStep === 1 && Object.keys(errors).length > 0}
              >
                Next
              </Button>
            ) : (
              <Button
                variant="primary"
                onClick={handleComplete}
              >
                Complete Setup
              </Button>
            )}
          </Row>
        </Card>
      </Stack>
    </Container>
  );
