// Place helper components here if needed
const getConditionVisual = (condition: string): { icon: string; label: string; badgeVariant: 'default' | 'success' | 'warning' | 'error' | 'info' | 'primary' | 'secondary' } => {
  const normalized = condition.toLowerCase();
  if (normalized.includes('sun') || normalized.includes('clear')) {
    return { icon: '☀️', label: 'Sunny', badgeVariant: 'warning' };
  }
  if (normalized.includes('cloud') || normalized.includes('overcast')) {
    return { icon: '☁️', label: 'Cloudy', badgeVariant: 'default' };
  }
  if (normalized.includes('rain') || normalized.includes('drizzle') || normalized.includes('shower')) {
    return { icon: '🌧️', label: 'Rainy', badgeVariant: 'info' };
  }
  if (normalized.includes('storm') || normalized.includes('thunder')) {
    return { icon: '⛈️', label: 'Stormy', badgeVariant: 'error' };
  }
  if (normalized.includes('snow') || normalized.includes('sleet') || normalized.includes('ice')) {
    return { icon: '❄️', label: 'Snowy', badgeVariant: 'primary' };
  }
  if (normalized.includes('fog') || normalized.includes('mist') || normalized.includes('haze')) {
    return { icon: '🌫️', label: 'Foggy', badgeVariant: 'secondary' };
  }
  if (normalized.includes('wind')) {
    return { icon: '💨', label: 'Windy', badgeVariant: 'default' };
  }
  return { icon: '🌤️', label: condition, badgeVariant: 'default' };
};

