import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





// Place helper components here if needed

const TOTAL_STEPS = 5;

function isValidEmail(email: string): boolean {
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
}

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const submit = useAction<ActionSubmitPayload>('submit'); // Called with all collected answers as a structured object
  const [currentStep, setCurrentStep] = useState<number>(1);
  const [name, setName] = useState<string>('');
  const [email, setEmail] = useState<string>('');
  const [satisfaction, setSatisfaction] = useState<number>(0);
  const [features, setFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState<string>('');
  const [touchedName, setTouchedName] = useState<boolean>(false);
  const [touchedEmail, setTouchedEmail] = useState<boolean>(false);
  const [touchedSatisfaction, setTouchedSatisfaction] = useState<boolean>(false);

  const progressValue = useMemo(() => (currentStep / TOTAL_STEPS) * 100, [currentStep]);
  const safeFeatureOptions = useMemo(() => props.featureOptions ?? [], [props.featureOptions]);
  const safeSatisfactionLabels = useMemo(() => props.satisfactionLabels ?? [], [props.satisfactionLabels]);

  const nameError = useMemo(() => {
    if (!touchedName) return '';
    if (!name.trim()) return 'Name is required.';
    return '';
  }, [name, touchedName]);

  const emailError = useMemo(() => {
    if (!touchedEmail) return '';
    if (!email.trim()) return 'Email is required.';
    if (!isValidEmail(email.trim())) return 'Please enter a valid email address.';
    return '';
  }, [email, touchedEmail]);

  const satisfactionError = useMemo(() => {
    if (!touchedSatisfaction) return '';
    if (satisfaction < 1 || satisfaction > 5) return 'Please select a satisfaction rating.';
    return '';
  }, [satisfaction, touchedSatisfaction]);

  const step1Valid = useMemo(() => name.trim().length > 0 && isValidEmail(email.trim()), [name, email]);
  const step2Valid = useMemo(() => satisfaction >= 1 && satisfaction <= 5, [satisfaction]);
  const canProceed = useMemo(() => {
    if (currentStep === 1) return step1Valid;
    if (currentStep === 2) return step2Valid;
    return true;
  }, [currentStep, step1Valid, step2Valid]);

  const selectedSatisfactionLabel = useMemo(() => {
    if (satisfaction < 1 || satisfaction > 5) return 'Not selected';
    return safeSatisfactionLabels[satisfaction - 1] ?? `Rating ${satisfaction}`;
  }, [satisfaction, safeSatisfactionLabels]);

  const satisfactionOptions = useMemo(
    () =>
      [1, 2, 3, 4, 5].map((value) => ({
        value: String(value),
        label: safeSatisfactionLabels[value - 1] ?? `Rating ${value}`,
      })),
    [safeSatisfactionLabels],
  );

  const toggleFeature = useCallback((feature: string, checked: boolean) => {
    setFeatures((prev) => {
      if (checked) {
        if (prev.includes(feature)) return prev;
        return [...prev, feature];
      }
      return prev.filter((item) => item !== feature);
    });
  }, []);

  const goNext = useCallback(() => {
    if (currentStep === 1) {
      setTouchedName(true);
      setTouchedEmail(true);
      if (!step1Valid) return;
    }
    if (currentStep === 2) {
      setTouchedSatisfaction(true);
      if (!step2Valid) return;
    }
    setCurrentStep((prev) => (prev < TOTAL_STEPS ? prev + 1 : prev));
  }, [currentStep, step1Valid, step2Valid]);

  const goBack = useCallback(() => {
    setCurrentStep((prev) => (prev > 1 ? prev - 1 : prev));
  }, []);

  const handleSubmit = useCallback(() => {
    submit({
      name: name.trim(),
      email: email.trim(),
      satisfaction,
      features,
      comments: comments.trim(),
    });
  }, [submit, name, email, satisfaction, features, comments]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-5)" border shadow="sm">
          <Stack gap="var(--ggui-spacing-3)">
            <Row justify="between" align="center">
              <Heading level={3}>Multi-Step Survey</Heading>
              <Badge variant="primary">Step {currentStep} of {TOTAL_STEPS}</Badge>
            </Row>
            <Progress value={progressValue} max={100} size="md" />
          </Stack>
        </Card>

        <Card padding="var(--ggui-spacing-6)" border shadow="sm">
          <Stack gap="var(--ggui-spacing-4)">
            {currentStep === 1 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Your Details</Heading>
                <Input
                  label="Name"
                  value={name}
                  onChange={(value) => {
                    setName(value);
                    if (!touchedName) setTouchedName(true);
                  }}
                  required
                  placeholder="Enter your full name"
                  error={nameError || undefined}
                />
                <Input
                  label="Email"
                  type="email"
                  value={email}
                  onChange={(value) => {
                    setEmail(value);
                    if (!touchedEmail) setTouchedEmail(true);
                  }}
                  required
                  placeholder="you@example.com"
                  error={emailError || undefined}
                />
              </Stack>
            )}

            {currentStep === 2 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Satisfaction</Heading>
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                  Please choose one option from the scale provided.
                </Text>
                <RadioGroup
                  label="How satisfied are you?"
                  value={satisfaction > 0 ? String(satisfaction) : ''}
                  onChange={(value) => {
                    setSatisfaction(Number(value));
                    if (!touchedSatisfaction) setTouchedSatisfaction(true);
                  }}
                  options={satisfactionOptions}
                  error={satisfactionError || undefined}
                />
              </Stack>
            )}

            {currentStep === 3 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Feature Interests</Heading>
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                  Select all features that interest you.
                </Text>
                {safeFeatureOptions.length === 0 ? (
                  <Alert variant="info" title="No features available">
                    There are currently no feature options to choose from.
                  </Alert>
                ) : (
                  <Stack gap="var(--ggui-spacing-3)">
                    {safeFeatureOptions.map((feature) => (
                      <Checkbox
                        key={feature}
                        label={feature}
                        checked={features.includes(feature)}
                        onChange={(checked) => toggleFeature(feature, checked)}
                      />
                    ))}
                  </Stack>
                )}
              </Stack>
            )}

            {currentStep === 4 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Additional Comments</Heading>
                <TextArea
                  label="Comments (optional)"
                  value={comments}
                  onChange={(value) => setComments(value)}
                  placeholder="Share any additional feedback..."
                  maxLength={500}
                  showCount
                  helperText="Maximum 500 characters"
                  rows={6}
                />
              </Stack>
            )}

            {currentStep === 5 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Review Your Responses</Heading>
                <Card padding="var(--ggui-spacing-4)" border shadow="none">
                  <Stack gap="var(--ggui-spacing-3)">
                    <Row justify="between">
                      <Text variant="label">Name</Text>
                      <Text>{name || '—'}</Text>
                    </Row>
                    <Divider margin="var(--ggui-spacing-2)" />
                    <Row justify="between">
                      <Text variant="label">Email</Text>
                      <Text>{email || '—'}</Text>
                    </Row>
                    <Divider margin="var(--ggui-spacing-2)" />
                    <Row justify="between">
                      <Text variant="label">Satisfaction</Text>
                      <Text>{selectedSatisfactionLabel}</Text>
                    </Row>
                    <Divider margin="var(--ggui-spacing-2)" />
                    <Stack gap="var(--ggui-spacing-2)">
                      <Text variant="label">Feature Interests</Text>
                      {features.length > 0 ? (
                        <Row wrap gap="var(--ggui-spacing-2)">
                          {features.map((feature) => (
                            <Tag key={feature} variant="primary">
                              {feature}
                            </Tag>
                          ))}
                        </Row>
                      ) : (
                        <Text color="var(--ggui-color-onSurfaceVariant)">None selected</Text>
                      )}
                    </Stack>
                    <Divider margin="var(--ggui-spacing-2)" />
                    <Stack gap="var(--ggui-spacing-2)">
                      <Text variant="label">Comments</Text>
                      <Text color="var(--ggui-color-onSurfaceVariant)">{comments.trim() || 'No comments provided'}</Text>
                    </Stack>
                  </Stack>
                </Card>
              </Stack>
            )}

            <Divider margin="var(--ggui-spacing-2)" />

            <Row justify="between" align="center">
              <Button
                variant="outline"
                disabled={currentStep === 1}
                as={Clickable}
                onClick={goBack}
              >
                Back
              </Button>

              {currentStep < TOTAL_STEPS ? (
                <Button
                  variant="primary"
                  disabled={!canProceed}
                  as={Clickable}
                  onClick={goNext}
                >
                  Next
                </Button>
              ) : (
                <Button variant="primary" as={Clickable} onClick={handleSubmit}>
                  Submit Survey
                </Button>
              )}
            </Row>
          </Stack>
        </Card>
      </Stack>
    </Container>

  );
}

