function getPriorityVariant(priority: 'low' | 'medium' | 'high'): 'success' | 'warning' | 'error' {
  if (priority === 'high') return 'error';
  if (priority === 'medium') return 'warning';
  return 'success';
}

function normalizeTask(
  task: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string },
  fallbackColumn: string,
  index: number,
): BoardTask {
  return {
    id: task.id && task.id.length > 0 ? task.id : `task-${index}-${Date.now()}` ,
    title: task.title && task.title.length > 0 ? task.title : 'Untitled Task',
    priority: task.priority ?? 'medium',
    assignee: task.assignee && task.assignee.length > 0 ? task.assignee : 'UN',
    column: task.column && task.column.length > 0 ? task.column : fallbackColumn,
    dueDate: task.dueDate,
  };
}

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate'); // Called when a task is moved, edited, or created. Payload: { action, taskId, data }

  // Streams — real-time from agent (.latest, .all)
  const taskChanged = useStream<StreamTaskChanged>('taskChanged'); // A task was moved, edited, or created by another user — update it in the board

  const defaultColumnId = useMemo(() => {
    if (props.columns && props.columns.length > 0 && props.columns[0]?.id) {
      return props.columns[0].id;
    }
    return 'todo';
  }, [props.columns]);

  const [tasksState, setTasksState] = useState<BoardTask[]>([]);
  const [isAddingByColumn, setIsAddingByColumn] = useState<Record<string, boolean>>({});
  const [newTitleByColumn, setNewTitleByColumn] = useState<Record<string, string>>({});
  const [newPriorityByColumn, setNewPriorityByColumn] = useState<Record<string, 'low' | 'medium' | 'high'>>({});
  const [editingTaskId, setEditingTaskId] = useState<string>('');
  const [editingTitle, setEditingTitle] = useState<string>('');

  useEffect(() => {
    const normalized = (props.tasks ?? []).map((task, index) => normalizeTask(task, defaultColumnId, index));
    setTasksState(normalized);
  }, [props.tasks, defaultColumnId]);

  useEffect(() => {
    if (!taskChanged.latest || !taskChanged.latest.task) return;
    const streamTask = normalizeTask(taskChanged.latest.task, defaultColumnId, taskChanged.all.length);

    setTasksState((prev) => {
      if (taskChanged.latest?.action === 'delete') {
        return prev.filter((t) => t.id !== streamTask.id);
      }
      const exists = prev.some((t) => t.id === streamTask.id);
      if (!exists) return [...prev, streamTask];
      return prev.map((t) => (t.id === streamTask.id ? { ...t, ...streamTask } : t));
    });
  }, [taskChanged.latest, taskChanged.all.length, defaultColumnId]);

  const taskCounts = useMemo(() => {
    const total = tasksState.length;
    const doneColumn = (props.columns ?? []).find((c) => (c.name ?? '').toLowerCase() === 'done')?.id ?? 'done';
    const completed = tasksState.filter((task) => task.column === doneColumn).length;
    return { total, completed };
  }, [tasksState, props.columns]);

  const moveTask = useCallback(
    (taskId: string, targetColumn: string) => {
      setTasksState((prev) => prev.map((task) => (task.id === taskId ? { ...task, column: targetColumn } : task)));
      taskUpdate({ action: 'move', taskId, data: { column: targetColumn } });
    },
    [taskUpdate],
  );

  const startEditTask = useCallback((task: BoardTask) => {
    setEditingTaskId(task.id);
    setEditingTitle(task.title);
  }, []);

  const saveEditTask = useCallback(
    (taskId: string) => {
      if (!editingTitle.trim()) return;
      const existingTask = tasksState.find((task) => task.id === taskId);
      const updatedTask = {
        ...(existingTask ?? { id: taskId, column: defaultColumnId, priority: 'medium' as const, assignee: 'UN', title: editingTitle.trim() }),
        title: editingTitle.trim(),
      };
      setTasksState((prev) => prev.map((task) => (task.id === taskId ? { ...task, title: editingTitle.trim() } : task)));
      setEditingTaskId('');
      setEditingTitle('');
      taskUpdate({
        action: 'edit',
        taskId,
        data: {
          column: updatedTask.column,
          title: updatedTask.title,
          priority: updatedTask.priority,
          assignee: updatedTask.assignee,
          dueDate: updatedTask.dueDate,
        } as unknown as { column: string },
      });
    },
    [editingTitle, taskUpdate, tasksState, defaultColumnId],
  );


  const addTask = useCallback(
    (columnId: string) => {
      const title = (newTitleByColumn[columnId] ?? '').trim();
      if (!title) return;
      const priority = newPriorityByColumn[columnId] ?? 'medium';
      const newTask: BoardTask = {
        id: `task-${Date.now()}`,
        title,
        priority,
        assignee: 'ME',
        column: defaultColumnId,
      };
      setTasksState((prev) => [...prev, newTask]);
      setNewTitleByColumn((prev) => ({ ...prev, [columnId]: '' }));
      setNewPriorityByColumn((prev) => ({ ...prev, [columnId]: 'medium' }));
      setIsAddingByColumn((prev) => ({ ...prev, [columnId]: false }));
      taskUpdate({
        action: 'create',
        taskId: newTask.id,
        data: {
          column: newTask.column,
          title: newTask.title,
          priority: newTask.priority,
          assignee: newTask.assignee,
          dueDate: newTask.dueDate,
        } as unknown as { column: string },
      });
    },
    [newTitleByColumn, newPriorityByColumn, taskUpdate, defaultColumnId],
  );


  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-4)">
        <Card padding="var(--ggui-spacing-4)" shadow="sm">
          <Row justify="between" align="center">
            <Stack gap="var(--ggui-spacing-1)">
              <Heading level={3}>Team Task Board</Heading>
              <Text color="var(--ggui-color-onSurfaceVariant)">
                Total Tasks: {taskCounts.total} · Completed: {taskCounts.completed}
              </Text>
            </Stack>
            <Badge variant="primary">Live updates: {taskChanged.all.length}</Badge>
          </Row>
        </Card>

        {(props.columns ?? []).length === 0 ? (
          <Alert variant="warning" title="No columns available">
            No columns were provided.
          </Alert>
        ) : (
          <Row gap="var(--ggui-spacing-4)" align="start" wrap>
            {(props.columns ?? []).map((column, columnIndex) => {
              const columnId = column.id ?? `column-${columnIndex}`;
              const columnName = column.name ?? 'Untitled Column';
              const columnTasks = tasksState.filter((task) => task.column === columnId);

              return (
                <Card
                  key={columnId}
                  padding="var(--ggui-spacing-4)"
                  shadow="sm"
                  border
                >
                  <Stack gap="var(--ggui-spacing-3)">
                    <Row justify="between" align="center">
                      <Heading level={4}>{columnName}</Heading>
                      <Badge variant="default">{columnTasks.length}</Badge>
                    </Row>

                    <Stack gap="var(--ggui-spacing-2)">
                      {columnTasks.length === 0 ? (
                        <Text color="var(--ggui-color-onSurfaceVariant)">No tasks yet</Text>
                      ) : (
                        columnTasks.map((task) => {
                          const moveOptions = (props.columns ?? [])
                            .filter((c) => c.id && c.id !== task.column)
                            .map((c) => ({ value: c.id as string, label: c.name ?? (c.id as string) }));

                          return (
                            <Card key={task.id} padding="var(--ggui-spacing-3)" shadow="none" border>
                              <Stack gap="var(--ggui-spacing-2)">
                                <Row justify="between" align="center">
                                  {editingTaskId === task.id ? (
                                    <Input
                                      label="Edit task title"
                                      value={editingTitle}
                                      onChange={setEditingTitle}
                                      placeholder="Task title"
                                    />
                                  ) : (
                                    <Text
                                      as={Clickable}
                                      onClick={() => startEditTask(task)}
                                      onDoubleClick={() => startEditTask(task)}
                                      hoverStyle={{ color: 'var(--ggui-color-primary-700)', textDecoration: 'underline' }}
                                      pressStyle={{ color: 'var(--ggui-color-primary-800)' }}
                                      weight="medium"
                                    >
                                      {task.title}
                                    </Text>
                                  )}
                                  <Badge variant={getPriorityVariant(task.priority)}>{task.priority}</Badge>
                                </Row>

                                <Row justify="between" align="center">
                                  <Row gap="var(--ggui-spacing-2)" align="center">
                                    <Avatar name={task.assignee} size="sm" />
                                    <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                                      {task.assignee}
                                    </Text>
                                  </Row>
                                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                                    {task.dueDate ? `Due: ${task.dueDate}` : 'No due date'}
                                  </Text>
                                </Row>

                                <Row gap="var(--ggui-spacing-2)" align="center">
                                  {editingTaskId === task.id ? (
                                    <>
                                      <Button size="sm" onPress={() => saveEditTask(task.id)}>Save</Button>
                                      <Button
                                        size="sm"
                                        variant="ghost"
                                        onPress={() => {
                                          setEditingTaskId('');
                                          setEditingTitle('');
                                        }}
                                      >
                                        Cancel
                                      </Button>
                                    </>
                                  ) : (
                                    <Button size="sm" variant="outline" onPress={() => startEditTask(task)}>
                                      Edit
                                    </Button>
                                  )}

                                  <Select
                                    label="Move task"
                                    value=""
                                    onChange={(value) => moveTask(task.id, value)}
                                    placeholder="Move to..."
                                    options={moveOptions}
                                  />
                                </Row>
                              </Stack>
                            </Card>
                          );
                        })
                      )}
                    </Stack>

                    <Divider margin="var(--ggui-spacing-2)" />

                    {isAddingByColumn[columnId] ? (
                      <Card padding="var(--ggui-spacing-3)" shadow="none" border>
                        <Stack gap="var(--ggui-spacing-2)">
                          <Input
                            label="Task title"
                            value={newTitleByColumn[columnId] ?? ''}
                            onChange={(value) => setNewTitleByColumn((prev) => ({ ...prev, [columnId]: value }))}
                            placeholder="Enter task title"
                          />
                          <Select
                            label="Priority"
                            value={newPriorityByColumn[columnId] ?? 'medium'}
                            onChange={(value) => setNewPriorityByColumn((prev) => ({ ...prev, [columnId]: (value as 'low' | 'medium' | 'high') }))}
                            options={PRIORITY_OPTIONS}
                          />
                          <Row gap="var(--ggui-spacing-2)">
                            <Button size="sm" onPress={() => addTask(columnId)}>Create</Button>
                            <Button
                              size="sm"
                              variant="ghost"
                              onPress={() => setIsAddingByColumn((prev) => ({ ...prev, [columnId]: false }))}
                            >
                              Cancel
                            </Button>
                          </Row>
                        </Stack>
                      </Card>
                    ) : (
                      <Button
                        size="sm"
                        variant="ghost"
                        onPress={() => setIsAddingByColumn((prev) => ({ ...prev, [columnId]: true }))}
                      >
                        + Add Task
                      </Button>
                    )}
                  </Stack>
                </Card>
              );
            })}
          </Row>
        )}
      </Stack>
    </Container>

  );
}

