  const [searchQuery, setSearchQuery] = useState<string>('');
  const [selectedAtomicNumber, setSelectedAtomicNumber] = useState<number | null>(null);

  const filteredElements = useMemo(() => {
    const query = searchQuery.trim().toLowerCase();
    if (!Array.isArray(props.elements)) {
      return [];
    }
    if (!query) {
      return props.elements;
    }
    return props.elements.filter((element) => {
      const name = (element.name || '').toLowerCase();
      const symbol = (element.symbol || '').toLowerCase();
      return name.includes(query) || symbol.includes(query);
    });
  }, [props.elements, searchQuery]);

  const selectedElement = useMemo(() => {
    if (!Array.isArray(props.elements) || selectedAtomicNumber === null) {
      return null;
    }
    return props.elements.find((element) => element.atomicNumber === selectedAtomicNumber) || null;
  }, [props.elements, selectedAtomicNumber]);

  const categories = useMemo(() => {
    if (!Array.isArray(props.elements)) {
      return [];
    }
    const unique = new Set<string>();
    props.elements.forEach((element) => {
      unique.add(normalizeCategory(element.category));
    });
    return Array.from(unique).sort();
  }, [props.elements]);

  useEffect(() => {
    if (!Array.isArray(props.elements) || props.elements.length === 0) {
      setSelectedAtomicNumber(null);
      return;
    }
    if (selectedAtomicNumber === null) {
      return;
    }
    const stillExists = props.elements.some((element) => element.atomicNumber === selectedAtomicNumber);
    if (!stillExists) {
      setSelectedAtomicNumber(null);
    }
  }, [props.elements, selectedAtomicNumber]);

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-6)">
