                  const atomicNumber = element.atomicNumber || index + 1;
                  const isSelected = selectedAtomicNumber === atomicNumber;
                  return (
                    <Card
                      key={`${atomicNumber}-${element.symbol || index}`}
                      as={Clickable}
                      onClick={() => setSelectedAtomicNumber(atomicNumber)}
                      aria-label={`${element.name || 'Unknown'} (${element.symbol || '?' }), atomic number ${element.atomicNumber ?? '-'}`}
                      padding="var(--ggui-spacing-2)"
                      border
                      shadow={isSelected ? 'md' : 'none'}
                      hoverStyle={!isSelected ? {
