                        boxShadow: 'var(--ggui-shape-shadow-sm)',
                        outline: '2px solid var(--ggui-color-primary-300)',
                        outlineOffset: '2px',
                      } : undefined}
                      style={{
                        gridColumn: `${gridColumn} / span 1`,
                        gridRow: `${gridRow} / span 1`,
                        minHeight: '72px',
                        background: getCategoryColor(element.category),
                        position: 'relative',
                        transition: 'transform 200ms ease, box-shadow 200ms ease, outline-color 200ms ease',
                        outline: isSelected ? '2px solid var(--ggui-color-primary-600)' : '2px solid transparent',
                        outlineOffset: '2px',
                      }}
                    >
                      <Text
