                      >
                        {element.atomicNumber || '-'}
                      </Text>
                      <Stack justify="center" align="center" style={{ minHeight: '56px' }}>
                        <Text size="xl" weight="bold" align="center">
                          {element.symbol || '?'}
                        </Text>
                      </Stack>
                    </Card>
                  );
                })
              )}
            </Box>
