type StreamTyping = { sender?: string; active?: boolean };




// Place helper components here if needed

const formatTimestamp = (value?: string): string => {
  if (!value) return '—';
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) return '—';
  return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
};

type UiMessage = {
  sender: string;
  text: string;
  timestamp: string;
};

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const sendMessage = useAction<ActionSendMessagePayload>('sendMessage'); // Called when user sends a message. Payload: { text, timestamp }

  // Streams — real-time from agent (.latest, .all)
  const message = useStream<StreamMessage>('message'); // New message from another participant — append to message list
  const typing = useStream<StreamTyping>('typing'); // Typing indicator — show/hide based on active flag

  const [inputValue, setInputValue] = useState<string>('');
  const [messagesState, setMessagesState] = useState<UiMessage[]>(
    (props.messages || []).map((m, index) => ({
      sender: m.sender || 'Unknown',
      text: m.text || '',
      timestamp: m.timestamp || new Date(Date.now() + index).toISOString(),
    }))
  );
  const listRef = useRef<HTMLDivElement | null>(null);

  useEffect(() => {
    setMessagesState(
      (props.messages || []).map((m, index) => ({
        sender: m.sender || 'Unknown',
        text: m.text || '',
        timestamp: m.timestamp || new Date(Date.now() + index).toISOString(),
      }))
    );
  }, [props.messages]);

  useEffect(() => {
    if (!message.latest) return;
    setMessagesState((prev) => [
      ...prev,
      {
        sender: message.latest.sender || 'Unknown',
        text: message.latest.text || '',
        timestamp: message.latest.timestamp || new Date().toISOString(),
      },
    ]);
  }, [message.latest]);

  useEffect(() => {
    if (!listRef.current) return;
    listRef.current.scrollTop = listRef.current.scrollHeight;
  }, [messagesState, typing.latest]);

  const groupedMessages = useMemo(() => {
    const groups: Array<{ sender: string; items: UiMessage[] }> = [];
    messagesState.forEach((msg) => {
      const last = groups[groups.length - 1];
      if (last && last.sender === msg.sender) {
        last.items.push(msg);
      } else {
        groups.push({ sender: msg.sender, items: [msg] });
      }
    });
    return groups;
  }, [messagesState]);

  const typingText = useMemo(() => {
    if (!typing.latest || !typing.latest.active) return '';
    const typingSender = typing.latest.sender || 'Someone';
    if (typingSender === props.currentUser) return '';
    return typingSender + ' is typing...';
  }, [typing.latest, props.currentUser]);

  const handleSend = useCallback(() => {
    const trimmed = inputValue.trim();
    if (!trimmed) return;
    const timestamp = new Date().toISOString();
    sendMessage({ text: trimmed, timestamp });
    setMessagesState((prev) => [
      ...prev,
      { sender: props.currentUser, text: trimmed, timestamp },
    ]);
    setInputValue('');
  }, [inputValue, sendMessage, props.currentUser]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Card
        padding="var(--ggui-spacing-4)"
        radius="lg"
        shadow="sm"
        border
      >
