/** Stream event: Updated price data for one or more stocks */
type StreamPriceUpdate = { symbol?: string; price?: number; change?: number; changePercent?: number };

/** Stream event: Market open/closed status update */
type StreamMarketStatus = { status?: 'open' | 'closed' | 'pre-market' | 'after-hours'; timestamp?: string };




// Place helper components here if needed
function formatMoney(value: number): string {
  return `$${value.toFixed(2)}`;
}

function formatTimestamp(date: Date): string {
  return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', second: '2-digit' });
}

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract

  // Streams — real-time from agent (.latest, .all)
  const priceUpdate = useStream<StreamPriceUpdate>('priceUpdate'); // Updated price data for one or more stocks
  const marketStatus = useStream<StreamMarketStatus>('marketStatus'); // Market open/closed status update
  const [displayStocks, setDisplayStocks] = useState<Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>>(props.stocks ?? []);
  const [lastUpdated, setLastUpdated] = useState<Date>(new Date());
  const [tick, setTick] = useState<number>(0);
  const [flashMap, setFlashMap] = useState<Record<string, number>>({});

  useEffect(() => {
    setDisplayStocks(props.stocks ?? []);
  }, [props.stocks]);

  useEffect(() => {
    const interval = setInterval(() => {
      setTick((prev) => prev + 1);
    }, 1000);

    return () => {
      clearInterval(interval);
    };
  }, []);

  useEffect(() => {
    if (!priceUpdate.latest?.symbol) {
      return;
    }

    setDisplayStocks((prev) => {
      const found = prev.some((stock) => stock.symbol === priceUpdate.latest?.symbol);
      const next = prev.map((stock) => {
        if (stock.symbol !== priceUpdate.latest?.symbol) {
          return stock;
        }
        return {
          ...stock,
          price: priceUpdate.latest?.price ?? stock.price,
          change: priceUpdate.latest?.change ?? stock.change,
          changePercent: priceUpdate.latest?.changePercent ?? stock.changePercent,
        };
      });

      if (!found) {
        next.push({
          symbol: priceUpdate.latest?.symbol,
          name: priceUpdate.latest?.symbol,
          price: priceUpdate.latest?.price ?? 0,
          change: priceUpdate.latest?.change ?? 0,
          changePercent: priceUpdate.latest?.changePercent ?? 0,
        });
      }

      return next;
    });

    setLastUpdated(new Date());
    setFlashMap((prev) => ({
      ...prev,
      [priceUpdate.latest.symbol as string]: Date.now(),
    }));
  }, [priceUpdate.latest]);

  const marketBadgeVariant = useMemo(() => {
    if (marketStatus.latest?.status === 'open') {
      return 'success' as const;
    }
    if (marketStatus.latest?.status === 'closed') {
      return 'error' as const;
    }
    return 'warning' as const;
  }, [marketStatus.latest]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Row justify="between" align="center" wrap>
          <Stack gap="var(--ggui-spacing-1)">
            <Heading level={1} color="var(--ggui-color-onSurface)">
              Market Watch
            </Heading>
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
              Last Updated: {formatTimestamp(lastUpdated)}
            </Text>
          </Stack>
          <Row gap="var(--ggui-spacing-2)" align="center">
            <Badge variant={marketBadgeVariant}>
              {marketStatus.latest?.status ?? 'pre-market'}
            </Badge>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
              {marketStatus.latest?.timestamp ?? 'Live stream active'}
            </Text>
          </Row>
        </Row>

        <Divider margin="var(--ggui-spacing-2)" color="var(--ggui-color-outlineVariant)" />

        {displayStocks.length === 0 ? (
          <Card padding="var(--ggui-spacing-6)" shadow="sm" border>
            <Stack gap="var(--ggui-spacing-2)" align="center">
              <Text variant="body" color="var(--ggui-color-onSurface)">
                No stocks available
              </Text>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                Waiting for stock data from props or live stream.
              </Text>
            </Stack>
          </Card>
        ) : (
          <Box
            style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(3, minmax(0, 1fr))',
              gap: 'var(--ggui-spacing-4)',
            }}
          >
            {displayStocks.map((stock) => {
              const safePrice = stock.price ?? 0;
              const safeChange = stock.change ?? 0;
              const safePercent = stock.changePercent ?? 0;
              const isPositive = safeChange >= 0;
              const symbol = stock.symbol ?? 'N/A';
              const flashKey = flashMap[symbol] ?? 0;

              return (
                <Card
                  key={`${symbol}-${flashKey}`}
                  padding="var(--ggui-spacing-4)"
                  shadow="sm"
                  border
                  style={{
                    borderColor: isPositive ? 'var(--ggui-color-success-500)' : 'var(--ggui-color-error-500)',
                    animation: 'ggui-flash 300ms ease-out',
                    ['--ggui-flash-color' as string]: isPositive ? 'var(--ggui-color-success-100)' : 'var(--ggui-color-error-100)',
                  }}
                >
                  <Stack gap="var(--ggui-spacing-2)">
                    <Text size="2xl" weight="bold" color="var(--ggui-color-onSurface)">
                      {symbol}
                    </Text>
                    <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                      {stock.name ?? 'Unknown Company'}
                    </Text>
                    <Heading level={3} color="var(--ggui-color-onSurface)">
                      {formatMoney(safePrice)}
                    </Heading>
                    <Row justify="between" align="center">
                      <Text
                        variant="bodySmall"
                        color={isPositive ? 'var(--ggui-color-success-600)' : 'var(--ggui-color-error-600)'}
                      >
                        {isPositive ? '+' : ''}{safeChange.toFixed(2)}
                      </Text>
                      <Text
                        variant="label"
                        color={isPositive ? 'var(--ggui-color-success-600)' : 'var(--ggui-color-error-600)'}
                      >
                        {isPositive ? '▲' : '▼'} {isPositive ? '+' : ''}{safePercent.toFixed(2)}%
                      </Text>
                    </Row>
                  </Stack>
                </Card>
              );
            })}
          </Box>
        )}
      </Stack>
    </Container>

  );
}

