// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  initialProfile: { name?: string; email?: string; avatar?: string; role?: string; emailNotifications?: boolean; theme?: string }; // Pre-filled profile data for editing (all fields optional)
  avatarOptions: string[]; // Available avatar emojis to choose from
  roleOptions: string[]; // Available role options for the dropdown
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all profile data when user completes onboarding */
type ActionCompletePayload = { name: string; email: string; avatar: string; role: string; emailNotifications: boolean; theme: string };





const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const complete = useAction<ActionCompletePayload>('complete'); // Called with all profile data when user completes onboarding

  const safeAvatarOptions = useMemo(() => {
    const fromProps = props.avatarOptions && props.avatarOptions.length > 0 ? props.avatarOptions : ['😀', '😎', '🚀', '🌟'];
    return fromProps.slice(0, 4);
  }, [props.avatarOptions]);

  const safeRoleOptions = useMemo(() => {
    const defaults = ['Developer', 'Designer', 'Manager', 'Other'];
    return props.roleOptions && props.roleOptions.length > 0 ? props.roleOptions : defaults;
  }, [props.roleOptions]);

  const [step, setStep] = useState<number>(1);
  const [name, setName] = useState<string>(props.initialProfile?.name ?? '');
  const [email, setEmail] = useState<string>(props.initialProfile?.email ?? '');
  const [avatar, setAvatar] = useState<string>(props.initialProfile?.avatar ?? (safeAvatarOptions[0] ?? '😀'));
  const [role, setRole] = useState<string>(props.initialProfile?.role ?? '');
  const [emailNotifications, setEmailNotifications] = useState<boolean>(props.initialProfile?.emailNotifications ?? true);
  const [theme, setTheme] = useState<string>(props.initialProfile?.theme ?? 'light');
  const [showErrors, setShowErrors] = useState<boolean>(false);

  useEffect(() => {
    setName(props.initialProfile?.name ?? '');
    setEmail(props.initialProfile?.email ?? '');
    setAvatar(props.initialProfile?.avatar ?? (safeAvatarOptions[0] ?? '😀'));
    setRole(props.initialProfile?.role ?? '');
    setEmailNotifications(props.initialProfile?.emailNotifications ?? true);
    setTheme(props.initialProfile?.theme ?? 'light');
  }, [props.initialProfile, safeAvatarOptions]);

  const isEmailValid = useMemo(() => EMAIL_REGEX.test(email.trim()), [email]);
  const isStep1Valid = useMemo(() => name.trim().length > 0 && email.trim().length > 0 && isEmailValid && avatar.trim().length > 0, [name, email, isEmailValid, avatar]);
  const isStep2Valid = useMemo(() => role.trim().length > 0 && (theme === 'light' || theme === 'dark'), [role, theme]);
  const progressValue = useMemo(() => (step / 3) * 100, [step]);

  const goNext = useCallback(() => {
    if (step === 1 && !isStep1Valid) {
      setShowErrors(true);
      return;
    }
    if (step === 2 && !isStep2Valid) {
      setShowErrors(true);
      return;
    }
    setShowErrors(false);
    setStep((prev) => (prev < 3 ? prev + 1 : prev));
  }, [step, isStep1Valid, isStep2Valid]);

  const goBack = useCallback(() => {
    setShowErrors(false);
    setStep((prev) => (prev > 1 ? prev - 1 : prev));
  }, []);

  const onCompleteSetup = useCallback(() => {
    if (!isStep1Valid || !isStep2Valid) {
      setShowErrors(true);
      setStep(!isStep1Valid ? 1 : 2);
      return;
    }
    complete({
      name: name.trim(),
      email: email.trim(),
      avatar,
      role,
      emailNotifications,
      theme,
    });
  }, [isStep1Valid, isStep2Valid, complete, name, email, avatar, role, emailNotifications, theme]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-4)" shadow="sm" border>
          <Stack gap="var(--ggui-spacing-3)">
            <Row justify="between" align="center">
              <Heading level={3}>Onboarding Wizard</Heading>
              <Badge variant="primary">Step {step} of 3</Badge>
            </Row>
            <Progress value={progressValue} max={100} variant="default" size="md" />
            <Row gap="var(--ggui-spacing-2)">
              <Badge variant={step >= 1 ? 'primary' : 'default'}>1. Profile</Badge>
              <Badge variant={step >= 2 ? 'primary' : 'default'}>2. Preferences</Badge>
              <Badge variant={step >= 3 ? 'primary' : 'default'}>3. Review</Badge>
            </Row>
          </Stack>
        </Card>

        <Box>
          {step === 1 && (
            <Card padding="var(--ggui-spacing-6)" shadow="md" border>
              <Stack gap="var(--ggui-spacing-4)">
                <Box style={{ animation: 'ggui-fadeIn 200ms ease-out' }}>
                  <Heading level={4}>Profile Setup</Heading>
                  <Text color="var(--ggui-color-onSurfaceVariant)">Tell us about yourself.</Text>
                </Box>

                <Input
                  label="Name"
                  value={name}
                  onChange={setName}
                  required
                  placeholder="Enter your full name"
                  error={showErrors && name.trim().length === 0 ? 'Name is required.' : undefined}
                />

                <Input
                  label="Email"
                  type="email"
                  value={email}
                  onChange={setEmail}
                  required
                  placeholder="you@example.com"
                  error={showErrors && email.trim().length === 0 ? 'Email is required.' : showErrors && !isEmailValid ? 'Enter a valid email address.' : undefined}
                />

                <Stack gap="var(--ggui-spacing-2)">
                  <Text variant="label">Choose an avatar</Text>
                  <Row gap="var(--ggui-spacing-3)" wrap>
                    {safeAvatarOptions.map((option) => (
                      <Card
                        key={option}
                        as={Clickable}
                        onClick={() => setAvatar(option)}
                        padding="var(--ggui-spacing-3)"
                        border
                        shadow={avatar === option ? 'md' : 'sm'}
                        hoverStyle={{ opacity: 0.9 }}
                        style={{
                          background: avatar === option ? 'var(--ggui-color-primary-50)' : 'var(--ggui-color-surface)',
                          borderColor: avatar === option ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-outline)',
                          minWidth: '72px',
                          textAlign: 'center',
                        }}
                      >
                        <Stack gap="var(--ggui-spacing-1)" align="center">
                          <Text size="2xl">{option}</Text>
                          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                            {avatar === option ? 'Selected' : 'Select'}
                          </Text>
                        </Stack>
                      </Card>
                    ))}
                  </Row>
                </Stack>
              </Stack>
            </Card>
          )}

          {step === 2 && (
            <Card padding="var(--ggui-spacing-6)" shadow="md" border>
              <Stack gap="var(--ggui-spacing-4)">
                <Box style={{ animation: 'ggui-fadeIn 200ms ease-out' }}>
                  <Heading level={4}>Preferences</Heading>
                  <Text color="var(--ggui-color-onSurfaceVariant)">Customize your experience.</Text>
                </Box>

                <Select
                  label="Role"
                  value={role}
                  onChange={setRole}
                  placeholder="Select your role"
                  options={safeRoleOptions.map((opt) => ({ value: opt, label: opt }))}
                  required
                  error={showErrors && role.trim().length === 0 ? 'Role is required.' : undefined}
                />

                <Toggle
                  label="Email notifications"
                  checked={emailNotifications}
                  onChange={setEmailNotifications}
                  size="md"
                />

                <Stack gap="var(--ggui-spacing-2)">
                  <Text variant="label">Theme preference</Text>
                  <Row gap="var(--ggui-spacing-3)">
                    <Card
                      as={Clickable}
                      onClick={() => setTheme('light')}
                      padding="var(--ggui-spacing-3)"
                      border
                      hoverStyle={{ opacity: 0.9 }}
                      style={{
                        background: theme === 'light' ? 'var(--ggui-color-primary-50)' : 'var(--ggui-color-surface)',
                        borderColor: theme === 'light' ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-outline)',
                        flex: 1,
                      }}
                    >
                      <Row justify="between" align="center">
                        <Text>Light</Text>
                        {theme === 'light' && <Badge variant="success" size="sm">Selected</Badge>}
                      </Row>
                    </Card>
                    <Card
                      as={Clickable}
                      onClick={() => setTheme('dark')}
                      padding="var(--ggui-spacing-3)"
                      border
                      hoverStyle={{ opacity: 0.9 }}
                      style={{
                        background: theme === 'dark' ? 'var(--ggui-color-primary-50)' : 'var(--ggui-color-surface)',
                        borderColor: theme === 'dark' ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-outline)',
                        flex: 1,
                      }}
                    >
                      <Row justify="between" align="center">
                        <Text>Dark</Text>
                        {theme === 'dark' && <Badge variant="success" size="sm">Selected</Badge>}
                      </Row>
                    </Card>
                  </Row>
                </Stack>
              </Stack>
            </Card>
          )}

          {step === 3 && (
            <Card padding="var(--ggui-spacing-6)" shadow="md" border>
              <Stack gap="var(--ggui-spacing-4)">
                <Box style={{ animation: 'ggui-fadeIn 200ms ease-out' }}>
                  <Heading level={4}>Review & Confirm</Heading>
                  <Text color="var(--ggui-color-onSurfaceVariant)">Please verify your details before completing setup.</Text>
                </Box>

                <Card padding="var(--ggui-spacing-4)" border shadow="sm">
                  <Stack gap="var(--ggui-spacing-2)">
                    <Row justify="between"><Text variant="label">Name</Text><Text>{name || '-'}</Text></Row>
                    <Divider margin="var(--ggui-spacing-1)" />
                    <Row justify="between"><Text variant="label">Email</Text><Text>{email || '-'}</Text></Row>
                    <Divider margin="var(--ggui-spacing-1)" />
                    <Row justify="between"><Text variant="label">Avatar</Text><Text>{avatar || '-'}</Text></Row>
                    <Divider margin="var(--ggui-spacing-1)" />
                    <Row justify="between"><Text variant="label">Role</Text><Text>{role || '-'}</Text></Row>
                    <Divider margin="var(--ggui-spacing-1)" />
                    <Row justify="between"><Text variant="label">Email Notifications</Text><Text>{emailNotifications ? 'On' : 'Off'}</Text></Row>
                    <Divider margin="var(--ggui-spacing-1)" />
                    <Row justify="between"><Text variant="label">Theme</Text><Text>{theme}</Text></Row>
                  </Stack>
                </Card>
              </Stack>
            </Card>
          )}
        </Box>

        <Row justify="between" align="center">
          <Button variant="ghost" onClick={goBack} disabled={step === 1}>
            Back
          </Button>

          <Row gap="var(--ggui-spacing-2)">
            {step < 3 && (
              <Button
                variant="primary"
                onClick={goNext}
                disabled={(step === 1 && !isStep1Valid) || (step === 2 && !isStep2Valid)}
              >
                Next
              </Button>
            )}
            {step === 3 && (
              <>
                <Button variant="outline" onClick={goBack}>Go Back</Button>
                <Button variant="primary" onClick={onCompleteSetup}>Complete Setup</Button>
              </>
            )}
          </Row>
        </Row>
      </Stack>
    </Container>

  );
}
